import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input too long. Please enter a name with maximum 10 characters.");
            return;
        }

        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0);

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
